issues = []
for nb in new_books:
    d = len(nb["description"])
    if d < 125 or d > 150:
        issues.append(f"Book {nb['id']} description: {d} chars")
    for i, t in enumerate(nb["thoughts"]):
        total = len(t["title"]) + len(t["example"])
        if total < 600 or total > 800:
            issues.append(f"Book {nb['id']} thought {i} ({t['title'][:25]}): {total}")

with open("/root/books/webapp/books.json") as f:
    books = json.load(f)
for nb in new_books:
    books.append(nb)
with open("/root/books/webapp/books.json", "w", encoding="utf-8") as f:
    json.dump(books, f, ensure_ascii=False, separators=(",", ":"))

if issues:
    print("Saved with issues:")
    for iss in issues: print(" ", iss)
else:
    print("OK - all 5 books saved, all lengths valid")
